#!/usr/bin/env python3
from sage.all import *
import time, signal

N = Integer()
print(f'N bits={N.nbits()}', flush=True)

class Timeout(Exception):
    pass

def handler(signum, frame):
    raise Timeout()

signal.signal(signal.SIGALRM, handler)

print('[*] Sage factor(Integer(N)) attempt (120s cap)...', flush=True)
t0=time.time()
try:
    signal.alarm(120)
    f = factor(N)
    signal.alarm(0)
    print('[+] factor() result:', f, flush=True)
except Timeout:
    print('[-] factor() timed out after 120s', flush=True)
except Exception as e:
    print('[-] factor() exception:', e, flush=True)
finally:
    signal.alarm(0)
print('[*] elapsed %.2f'%(time.time()-t0), flush=True)

print('[*] PARI pollardpm1 attempts...', flush=True)
for B in [10^5,10^6,10^7,10^8]:
    t=time.time()
    try:
        gi = Integer(pari(f'pollardpm1({N},{B})'))
        if 1 < gi < N and N%gi==0:
            print(f'[+] pollardpm1 hit B={B}: {gi}', flush=True)
            print('cofactor=',N//gi, flush=True)
            raise SystemExit
    except Exception as e:
        print(f'  pollardpm1 B={B} err {e}', flush=True)
    print(f'  pollardpm1 B={B} done in {time.time()-t:.2f}s', flush=True)

print('[*] ECM attempts via PARI ecm...', flush=True)
found=[]
for B1,curves in [(2000,100),(5000,200),(11000,400),(50000,800),(250000,1200),(1000000,2000)]:
    t=time.time()
    print(f'  [*] B1={B1} curves={curves}', flush=True)
    for i in range(curves):
        try:
            fi = Integer(pari(f'ecm({B1},{N})'))
        except Exception:
            fi = Integer(1)
        if 1 < fi < N and N % fi == 0:
            print(f'[+] factor found with ECM curve {i+1}: {fi}', flush=True)
            print('cofactor=', N//fi, flush=True)
            found=[fi,N//fi]
            break
        if (i+1)%100==0:
            print(f'    ... {i+1} curves', flush=True)
    print(f'    elapsed {time.time()-t:.2f}s', flush=True)
    if found:
        break

if found:
    p,q=map(Integer,found)
    if p>q: p,q=q,p
    print('[+] p=',p, flush=True)
    print('[+] q=',q, flush=True)
else:
    print('[-] No factors found in configured budget', flush=True)

