from sage.all import *
from cysignals.alarm import alarm, cancel_alarm, AlarmInterrupt
import time
N=Integer()
print('[*] N bits',N.nbits(), flush=True)
t0=time.time()
# direct factor attempt bounded
try:
    alarm(45)
    fac=factor(N)
    cancel_alarm()
    print('[*] factor(N)=',fac,'time',time.time()-t0, flush=True)
except AlarmInterrupt:
    print('[*] factor(N) timed out after 45s',flush=True)
except Exception as e:
    print('[*] factor(N) exception',e,flush=True)

for B1 in [1000,5000,20000,100000,500000,2000000,5000000]:
    try:
        f=Integer(pari(N).pollardpm1(B1))
    except Exception:
        f=1
    print(f'[*] pollard p-1 B1={B1}:',('factor='+str(f) if (1<f<N and N%f==0) else 'no'),flush=True)

for B1 in [10000,100000,500000,2000000,5000000]:
    try:
        f=williams_pp1(N,B1)
    except Exception:
        f=1
    print(f'[*] williams p+1 B1={B1}:',('factor='+str(f) if (1<f<N and N%f==0) else 'no'),flush=True)

found=None
for B1,curves in [(2000,80),(5000,100),(10000,120),(20000,120),(50000,140),(100000,150),(200000,150)]:
    print(f'[*] ECM stage B1={B1}, curves={curves}, elapsed={time.time()-t0:.1f}s',flush=True)
    for i in range(curves):
        if time.time()-t0>600:
            break
        try:
            f=Integer(pari(N).ecm(B1))
        except Exception:
            continue
        if 1<f<N and N%f==0:
            found=f
            print('[+] ECM found factor',f,'curve',i,flush=True)
            break
    if found or time.time()-t0>600:
        break
if not found:
    print('[-] No factor found in budget. total',time.time()-t0,flush=True)

