#!/usr/bin/env python3
from pwn import remote
import re, random

def recv_init(io):
    txt=b""
    vals={}
    flag=None
    while True:
        line=io.recvline(timeout=5)
        if not line: break
        txt+=line
        s=line.decode(errors='ignore').strip()
        m=re.match(r"(N|G|publ|alice|nbits) = ([0-9]+)",s)
        if m: vals[m.group(1)]=int(m.group(2))
        if s.startswith('FLAG = '):
            flag=s.split('=',1)[1].strip(); break
    return vals,flag,txt.decode(errors='ignore')

io=remote('crypto.chal.csaw.io',5000)
vals,flag,banner=recv_init(io)
N,G,nbits=vals['N'],vals['G'],vals['nbits']
t=nbits-123
print('[*] nbits',nbits,'t',t)
print('[*] enc flag',flag)
cache={}
def ask(y):
    io.sendline(str(y).encode())
    return io.recvline(timeout=3).strip()

def bit_of_exp(k):
    if k in cache: return cache[k]
    y=pow(G,k,N)
    r=ask(y)
    if r==b'-1': cache[k]=None
    else:
        try: cache[k]=int(r)
        except: cache[k]=None
    return cache[k]

for _ in range(5):
    z=random.getrandbits(256)
    print('sample',bit_of_exp(z))

base=1<<t
for m in [1,2,3,5,7,11,13,17,31,63]:
    r=m*base
    ok=tot=unk=0
    for _ in range(80):
        z=random.getrandbits(256)
        b1=bit_of_exp(z); b2=bit_of_exp(z+r)
        if b1 is None or b2 is None: unk+=1; continue
        tot+=1; ok+= (b1==b2)
    print(f'm={m}: eq={ok}/{tot}, unk={unk}')
io.close()

