print('elapsed',time.time()-start)

print('[*] pari factor()')
start=time.time()
try:
    print(pari('factor(%s)'%str(N)))
except Exception as e:
    print('pari factor failed',e)
print('elapsed',time.time()-start)

rem=N
found=[]
for B1 in [2000,5000,10000,20000,50000,100000,200000,500000,1000000,2000000]:
    if rem.is_prime():
        found.append(rem); rem=Integer(1); break
    print(f'[*] ECM trying B1={B1}, rem bits={rem.nbits()}')
    t0=time.time()
    fac=None
    for _ in range(80):
        try:
            fac=ecm.find_factor(rem, B1=B1)
        except Exception:
            fac=None
        if fac not in [None,1, rem]:
            break
    print('  done in',time.time()-t0,'fac=',fac)
    if fac not in [None,1,rem]:
        fac=Integer(fac)
        found.append(fac)
        rem//=fac
        print('  updated rem bits',rem.nbits())
    if time.time()-start>600:
        break

print('found factors partial',found,'rem',rem)
if rem>1:
    try:
        print('factor(rem)=',factor(rem))
    except Exception as e:
        print('factor rem fail',e)

