from sage.all import *
import time,sys
N=Integer()
print('Nbits',N.nbits());sys.stdout.flush()

start=time.time()
print('[1] trial factor() start');sys.stdout.flush()
try:
    f=factor(N)
    print('[1] factor=',f)
except Exception as e:
    print('[1] exception',e)
print('[1] elapsed',time.time()-start);sys.stdout.flush()

print('[2] Pollard p-1 attempts')
for B in [10^4,10^5,10^6,10^7]:
    t=time.time()
    try:
        g=pollard_pm1(N,B)
    except Exception as e:
        g=None
    print('B',B,'g',g,'time',time.time()-t);sys.stdout.flush()
    if g not in [None,1,N]:
        print('found',g,N//g);sys.exit(0)

print('[3] ECM loops')
rem=N
for B1 in [2000,5000,10000,20000,50000,100000,200000,500000,1000000,2000000,5000000]:
    if rem.is_prime():
        print('rem prime',rem);break
    for curves in [20,50,100,200]:
        t=time.time()
        fac=None
        for i in range(curves):
            try:
                fac=ecm.find_factor(rem,B1=B1)
            except Exception:
                fac=None
            if fac not in [None,1,rem]:
                break
        print('B1',B1,'curves',curves,'fac',fac,'time',time.time()-t);sys.stdout.flush()
        if fac not in [None,1,rem]:
            fac=Integer(fac)
            print('FOUND',fac,rem//fac);sys.exit(0)
        if time.time()-start>600:
            print('timeout 600s');sys.exit(1)
print('no factor found')

